// vbaParserInit initializes any static state used to implement vbaParser. By default the
// static state used to implement the parser is lazily initialized during the first call to
// NewvbaParser(). You can call this function if you wish to initialize the static state ahead
// of time.
func VbaParserInit() {
	staticData := &VbaParserStaticData
	staticData.once.Do(vbaParserInit)
}

// NewvbaParser produces a new parser instance for the optional input antlr.TokenStream.
func NewvbaParser(input antlr.TokenStream) *vbaParser {
	VbaParserInit()
	this := new(vbaParser)
	this.BaseParser = antlr.NewBaseParser(input)
	staticData := &VbaParserStaticData
	this.Interpreter = antlr.NewParserATNSimulator(this, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	this.RuleNames = staticData.RuleNames
	this.LiteralNames = staticData.LiteralNames
	this.SymbolicNames = staticData.SymbolicNames
	this.GrammarFileName = "vba.g4"

	return this
}

